import{_ as e,o as s,c as i,a2 as t}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"المشرف الفائق (Super Admin)","description":"","frontmatter":{},"headers":[],"relativePath":"ar/features/super-admin.md","filePath":"ar/features/super-admin.md"}'),c={name:"ar/features/super-admin.md"};function d(n,a,l,r,o,p){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="المشرف-الفائق-super-admin" tabindex="-1">المشرف الفائق (Super Admin) <a class="header-anchor" href="#المشرف-الفائق-super-admin" aria-label="Permalink to &quot;المشرف الفائق (Super Admin)&quot;">​</a></h1><p>يُنشأ دور <code>super_admin</code> تلقائياً بواسطة <code>clearance:install</code> ويُبقى متزامناً مع جميع صلاحيات <code>clearance-*</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install and make user ID 1 a super admin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=1</span></span></code></pre></div><p>انظر <a href="/clearance-docs/ar/guide/installation.html">دليل التثبيت</a> و<a href="/clearance-docs/ar/api/artisan-commands.html">مرجع أوامر Artisan</a> للاطلاع على قائمة خيارات أداة التثبيت الكاملة.</p><h2 id="تجاوز-gate-اختياري" tabindex="-1">تجاوز Gate (اختياري) <a class="header-anchor" href="#تجاوز-gate-اختياري" aria-label="Permalink to &quot;تجاوز Gate (اختياري)&quot;">​</a></h2><p>يتحكم <code>super_admin_gate_bypass</code> فيما إذا كان دور <code>super_admin</code> يتجاوز جميع فحوصات <code>can()</code> / <code>Gate::allows()</code> / السياسات (policies) الخاصة بـ Laravel على مستوى التطبيق بأكمله، عبر خطاف (hook) من نوع <code>Gate::before()</code>. الافتراضي: <code>false</code>. التجاوز اختياري. لتفعيله:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;super_admin_gate_bypass&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">على مستوى التطبيق بأكمله، وليس مقيّداً باللوحة</p><p>عند التفعيل، يتخطى أي مستخدم يحمل <code>super_admin</code> <strong>جميع</strong> فحوصات Gate على مستوى التطبيق بأكمله - وليس فقط فحوصات لوحة Clearance. يؤثر هذا على كل فحص <code>can()</code>، و<code>Gate::allows()</code>، وسياسة (policy) في تطبيقك، وليس فقط تلك التي تُعرّفها Clearance. لنطاق أضيق، اتركه معطّلاً وامنح الصلاحيات صراحةً بدلاً من ذلك.</p></div><h2 id="كشف-الأسماء-البديلة" tabindex="-1">كشف الأسماء البديلة <a class="header-anchor" href="#كشف-الأسماء-البديلة" aria-label="Permalink to &quot;كشف الأسماء البديلة&quot;">​</a></h2><p>إذا كانت قاعدة بياناتك تحتوي بالفعل على دور باسم <code>super_admin</code>، أو <code>superadmin</code>، أو <code>super-admin</code>، أو <code>root</code>، أو <code>owner</code>، تكتشفه أداة التثبيت وتُطالبك تفاعلياً بترقيته أو إنشاء <code>super_admin</code> منفصل. استخدم <code>--super-admin-role=NAME</code> لتخطي المطالبة:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clearance:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --super-admin-role=owner</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">الترقية غير هدّامة</p><p>تُعيد الترقية تسمية الدور في مكانه - تُحفظ جميع تعيينات <code>model_has_roles</code> الموجودة عبر المفتاح الخارجي (FK) على <code>role_id</code>. لا يفقد أي مستخدم تعيين دوره الموجود أثناء الترقية.</p></div><h2 id="الوصول-إلى-اللوحة-وصلاحيات-الكتابة-الدقيقة-التحكم" tabindex="-1">الوصول إلى اللوحة وصلاحيات الكتابة الدقيقة التحكم <a class="header-anchor" href="#الوصول-إلى-اللوحة-وصلاحيات-الكتابة-الدقيقة-التحكم" aria-label="Permalink to &quot;الوصول إلى اللوحة وصلاحيات الكتابة الدقيقة التحكم&quot;">​</a></h2><p>انتقل إلى <code>/clearance</code> بعد التثبيت. يتطلب الوصول للقراءة إلى اللوحة بأكملها صلاحية <code>clearance-access</code>، يُتحقق منها عبر <code>can()</code>، وليس أبداً عبر <code>hasRole()</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>عمليات الكتابة على كل قسم مقيّدة بصلاحية مخصصة قابلة للتفويض - جميعها تُنشأ بواسطة <code>clearance:install</code> وتُعيَّن لـ <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>الصلاحية</th><th>تتحكم في</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>إنشاء / تعديل / حذف الصلاحيات</td></tr><tr><td><code>clearance-roles-write</code></td><td>إنشاء / تعديل / حذف الأدوار وتعييناتها الخاصة بالصلاحيات</td></tr><tr><td><code>clearance-guards-write</code></td><td>إنشاء / تعديل / حذف الحراس</td></tr><tr><td><code>clearance-settings-write</code></td><td>تعديل بيانات العرض الوصفية، والأيقونات، والألوان، والدور الافتراضي</td></tr><tr><td><code>clearance-users-write</code></td><td>تعيين / إزالة الأدوار لمستخدم محدد</td></tr></tbody></table><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Grant a user write access to roles only:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-roles-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">منح وصول ضيّق النطاق</p><p>اجمع بين <code>clearance-access</code> وصلاحية واحدة بالضبط من نوع <code>clearance-{section}-write</code> لمنح مستخدم (قائد فريق مثلاً) وصول كتابة إلى قسم واحد من أقسام اللوحة - الأدوار، على سبيل المثال - دون كشف الإعدادات، أو الحراس، أو إدارة المستخدمين.</p></div><p>إذا لم يكن صف صلاحية دقيق التحكم موجوداً على الإطلاق في قاعدة البيانات (حالة قديمة سابقة للتزويد)، يعود الفحص إلى <code>clearance-access</code> للتوافق مع الإصدارات السابقة. على أي نسخة شغّلت <code>clearance:install</code>، لا يُفعَّل هذا الرجوع أبداً.</p><h2 id="صلاحيات-clearance-المحجوزة" tabindex="-1">صلاحيات <code>clearance-*</code> المحجوزة <a class="header-anchor" href="#صلاحيات-clearance-المحجوزة" aria-label="Permalink to &quot;صلاحيات \`clearance-*\` المحجوزة&quot;">​</a></h2><p>صلاحيات <code>clearance-*</code> محجوزة: لا يمكن إنشاؤها، أو إعادة تسميتها، أو حذفها، أو إضافتها إلى أي دور إلا عبر تدفق التثبيت الخاص بالحزمة نفسها - حتى بواسطة ممثل (actor) من نوع <code>super_admin</code> لدور <code>super_admin</code> نفسه.</p><h2 id="الخطوات-التالية" tabindex="-1">الخطوات التالية <a class="header-anchor" href="#الخطوات-التالية" aria-label="Permalink to &quot;الخطوات التالية&quot;">​</a></h2><ul><li><a href="/clearance-docs/ar/features/permissions.html">الصلاحيات</a> - لوحة CRUD الصلاحيات العامة (تستثني <code>clearance-*</code>).</li><li><a href="/clearance-docs/ar/features/roles.html">الأدوار</a> - تعيين صلاحيات <code>clearance-*-write</code> لدور مخصص.</li><li><a href="/clearance-docs/ar/guide/security.html">الأمان</a> - نموذج تصعيد الصلاحيات والسقف الكامل.</li></ul>`,24)])])}const u=e(c,[["render",d]]);export{k as __pageData,u as default};
